SELECT ?wickets WHERE {
  ?player wdt:P569 ?birthDate;
          wdt:P106 wd:Q192322;
          p:P54 ?teamStatement.

  ?teamStatement ps:P54 wd:Q220459;
               pq:P580 ?start;
               pq:P582 ?end.

  FILTER(year(?birthDate) = 1860)
  FILTER(?start <= "1881-01-01"^^xsd:dateTime)
  FILTER(?end >= "1898-12-31"^^xsd:dateTime)

  ?player p:P1262 ?wicketStatement.
  ?wicketStatement ps:P1262 ?wickets;
                   pq:P585 ?eventDate.
  FILTER(year(?eventDate) = 1895)
}

